import React, { useState, useEffect } from "react";

const API_URL = "https://laptimeapp-backend.onrender.com/api/laptimes";

function App() {
    const [lapTimes, setLapTimes] = useState([]);
    const [error, setError] = useState(null);

    // Fetch lap times on component load
    useEffect(() => {
        fetchLapTimes();
    }, []);

    const fetchLapTimes = async () => {
        try {
            const response = await fetch(API_URL);
            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }
            const data = await response.json();
            setLapTimes(data);
        } catch (err) {
            console.error("Error fetching lap times:", err);
            setError(err.message);
        }
    };

    return (
        <div>

            <div class="container">
            <div class="row">
                <div class="col-sm">
                One of three columns
                </div>
                <div class="col-sm">
                One of three columns
                </div>
                <div class="col-sm">
                One of three columns
                </div>
            </div>
            </div>
            <h1 id="p-3">Lap Times</h1>
            <div id="row">
                <div id="col">
                    <button onClick={fetchLapTimes}>Fetch Lap Times</button>
                </div>
            </div>
            
            {error && <p style={{ color: "red" }}>Error: {error}</p>}
            
            {/* Render Table */}
            {lapTimes.length > 0 ? (
                <table border="1" style={{ marginTop: "20px", width: "80%", textAlign: "left", borderCollapse: "collapse" }}>
                    <thead>
                        <tr>
                            <th>Driver</th>
                            <th>Track</th>
                            <th>Lap Time (s)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {lapTimes.map((lap, index) => (
                            <tr key={index}>
                                <td>{lap.driver}</td>
                                <td>{lap.track}</td>
                                <td>{lap.lapTime}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            ) : (
                <p>No lap times to display</p>
            )}
        </div>
    );
}

export default App;
